  53→
  54→function filterSections(sections: SectionData[], query: string): SectionData[] {
  55→  if (!query) return sections;
  56→  const lower = query.toLowerCase();
  57→  return sections
  58→    .map(section => ({
  59→      ...section,
  60→      items: section.items.filter(
  61→        item =>
  62→          item.title.toLowerCase().includes(lower) ||
  63→          item.subtitle?.toLowerCase().includes(lower),
  64→      ),
  65→    }))
  66→    .filter(section => section.items.length > 0);
  67→}
  68→
  69→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
  70→  if (!query) return colors;
  71→  const lower = query.toLowerCase();
  72→  return colors.filter(
  73→    c =>
  74→      c.title.toLowerCase().includes(lower) ||
  75→      c.subtitle?.toLowerCase().includes(lower),
  76→  );
  77→}
  78→
  79→function flattenItems(sections: SectionData[]): ListItemData[] {
  80→  return sections.flatMap(s => s.items);
  81→}
  82→
  83→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
  84→  switch (entry.type) {
  85→    case 'label':
  86→      return (
  87→        <DetailMetadata.Label
  88→          key={index}
  89→          title={entry.title}
  90→          text={entry.text}
  91→        />
  92→      );
  93→    case 'link':
  94→      return (
  95→        <DetailMetadata.Link
  96→          key={index}
  97→          title={entry.title}
  98→          text={entry.text}
  99→          target={entry.target}
 100→        />
 101→      );
 102→    case 'tag-list':
 103→      return (
 104→        <DetailMetadata.TagList key={index} title={entry.title}>
 105→          {entry.tags.map(tag => (
 106→            <DetailMetadata.Tag
 107→              key={tag.text}
 108→              text={tag.text}
 109→              color={tag.color}
 110→            />
 111→          ))}
 112→        </DetailMetadata.TagList>
 113→      );
 114→    case 'separator':
 115→      return <DetailMetadata.Separator key={index} />;
 116→  }
 117→}
 118→
