 186→
 187→interface ColorPickerViewProps {
 188→  colors: ColorItemData[];
 189→  onActiveIndexChange: (index: number) => void;
 190→  onAction: (index: number) => void;
 191→}
 192→
 193→function ColorPickerView({
 194→  colors,
 195→  onActiveIndexChange,
 196→  onAction,
 197→}: ColorPickerViewProps) {
 198→  if (colors.length === 0) {
 199→    return (
 200→      <EmptyState
 201→        icon={<SearchIcon />}
 202→        title="No Colors"
 203→        description="Try a different search term"
 204→      />
 205→    );
 206→  }
 207→
 208→  return (
 209→    <Grid
 210→      itemCount={colors.length}
 211→      columns={4}
 212→      onActiveIndexChange={onActiveIndexChange}
 213→      onAction={onAction}
 214→    >
 215→      {colors.map((color, index) => (
 216→        <GridItem
 217→          key={color.id}
 218→          index={index}
 219→          icon={<ColorSwatch color={color.color} />}
 220→          title={color.title}
 221→          subtitle={color.subtitle}
 222→        />
 223→      ))}
 224→    </Grid>
 225→  );
 226→}
 227→
 228→function DetailView({ item }: { item: ListItemData }) {
 229→  const itemDetail = item.detail;
 230→  if (!itemDetail) return null;
 231→  return (
 232→    <Detail
 233→      markdown={itemDetail.markdown}
 234→      metadata={
 235→        itemDetail.metadata ? (
 236→          <DetailMetadata>
 237→            {itemDetail.metadata.map(renderMetadataEntry)}
 238→          </DetailMetadata>
 239→        ) : undefined
 240→      }
 241→    />
 242→  );
