 586→    });
 587→  }, [
 588→    selectedItem,
 589→    toggleFavorite,
 590→    isFavorite,
 591→    showHUD,
 592→  ]);
 593→
 594→  useKeyboardShortcut(
 595→    {
 596→      key: 'f',
 597→      meta: true,
 598→      shift: true,
 599→    },
 600→    handleToggleFavorite,
 601→    { enabled: viewType === 'root' && !!selectedItem },
 602→  );
 603→
 604→  const handleMoveFavoriteUp = useCallback(() => {
 605→    if (!selectedItem || !isFavorite(selectedItem.id)) return;
 606→    moveFavorite(selectedItem.id, 'up');
