 608→  }, [
 609→    selectedItem,
 610→    isFavorite,
 611→    moveFavorite,
 612→  ]);
 613→
 614→  const handleMoveFavoriteDown = useCallback(() => {
 615→    if (!selectedItem || !isFavorite(selectedItem.id)) return;
 616→    moveFavorite(selectedItem.id, 'down');
 617→    setSelectedIndex(prev => prev + 1);
 618→  }, [
 619→    selectedItem,
 620→    isFavorite,
 621→    moveFavorite,
 622→  ]);
 623→
 624→  useKeyboardShortcut(
 625→    {
 626→      key: 'ArrowUp',
 627→      meta: true,
 628→      alt: true,
 629→    },
 630→    handleMoveFavoriteUp,
 631→    {
 632→      enabled:
 633→        viewType === 'root' && !!selectedItem && isFavorite(selectedItem.id),
 634→    },
 635→  );
 636→
 637→  useKeyboardShortcut(
 638→    {
 639→      key: 'ArrowDown',
 640→      meta: true,
 641→      alt: true,
 642→    },
 643→    handleMoveFavoriteDown,
 644→    {
 645→      enabled:
 646→        viewType === 'root' && !!selectedItem && isFavorite(selectedItem.id),
 647→    },
 648→  );
 649→
 650→  const openSettings = useCallback(() => {
 651→    if (viewType !== 'settings') {
 652→      push('Settings', { type: 'settings' });
 653→      setQuery('');
 654→      setSelectedIndex(0);
 655→      setActionsOpen(false);
 656→    }
